function random() {
  if (typeof crypto !== 'undefined' && typeof crypto.getRandomValues === 'function') {
    const arr = new Uint32Array(1);
    crypto.getRandomValues(arr);
    return arr[0] / 4294967296;
  }
  return Math.random();
}

export function getBasePPG(ovr, position) {
  const basePPG = ((ovr - 59) / 40) * 24 + 4;
  const positionMultiplier = {
    'PG': 0.9,
    'SG': 1.0,
    'SF': 1.05,
    'PF': 1.15,
    'C': 1.1,
  };
  return basePPG * (positionMultiplier[position] || 1.0);
}

export function getGameVariance() {
  const rand = random();
  if (rand > 0.85) return 5 + random() * 5;
  if (rand < 0.10) return -5 - random() * 5;
  return (random() - 0.5) * 6;
}

export function getMinutesPlayed(isStarter, requestedMinutes) {
  if (requestedMinutes) return requestedMinutes;
  if (isStarter) return 30 + Math.floor(random() * 8);
  return 8 + Math.floor(random() * 14);
}

// Generate realistic basketball stats that sum to team total
export function generateTeamBoxScore(players, teamScore, isWinner) {
  const boxScore = [];
  let pointsRemaining = teamScore;

  // Sort by OVR to determine rotation (top 10 players play in real NBA)
  const sortedPlayers = [...players].sort((a, b) => b.ovr - a.ovr);
  const rotation = sortedPlayers.slice(0, 10); // Only top 10 play
  const dnp = sortedPlayers.slice(10); // Rest get DNP

  // NBA-realistic usage rates based on OVR - MORE AGGRESSIVE
  const usageShares = rotation.map((player, index) => {
    const isStarter = index < 5;

    if (!isStarter) {
      // Bench players (6-10): low usage
      return 0.10 + (player.ovr / 100) * 0.08; // 0.10-0.18
    }

    // Starters (1-5): MUCH more aggressive usage for stars
    if (player.ovr >= 90) {
      // Superstar: 32-45% usage (can take over games)
      return 0.32 + (player.ovr - 90) * 0.013 + random() * 0.13;
    } else if (player.ovr >= 85) {
      // Star: 26-35% usage
      return 0.26 + (player.ovr - 85) * 0.018 + random() * 0.09;
    } else if (player.ovr >= 80) {
      // Good starter: 20-28% usage
      return 0.20 + (player.ovr - 80) * 0.016 + random() * 0.08;
    } else if (player.ovr >= 75) {
      // Decent starter: 16-22% usage
      return 0.16 + (player.ovr - 75) * 0.012 + random() * 0.06;
    } else {
      // Weak starter: 12-18% usage
      return 0.12 + (player.ovr - 65) * 0.006 + random() * 0.06;
    }
  });

  const totalUsage = usageShares.reduce((sum, u) => sum + u, 0);

  // Generate stats for rotation players
  rotation.forEach((player, index) => {
    const isStarter = index < 5;
    const minutes = getMinutesPlayed(isStarter, player.requestedMinutes);

    // Skip players with 0 minutes (DNP)
    if (minutes === 0) {
      boxScore.push({
        playerId: player.id,
        playerName: `${player.firstName} ${player.lastName}`,
        minutes: 0,
        points: 0,
        fgm: 0,
        fga: 0,
        tpm: 0,
        tpa: 0,
        ftm: 0,
        fta: 0,
        rebounds: 0,
        assists: 0,
        steals: 0,
        blocks: 0,
        turnovers: 0,
        fouls: 0,
      });
      return;
    }

    // Distribute points based on usage
    let points;
    const normalizedUsage = usageShares[index] / totalUsage;

    if (index === rotation.length - 1) {
      // Last rotation player gets remaining points
      points = Math.max(0, pointsRemaining);
    } else {
      const basePoints = teamScore * normalizedUsage;

      // Add hot/cold variance - superstars can REALLY go OFF
      let varianceMultiplier = 1.0;
      const hotColdRoll = random();

      if (player.ovr >= 88) {
        if (hotColdRoll > 0.85) {
          // Superstar explosion (15% chance) - 50-80% boost!
          varianceMultiplier = 1.5 + random() * 0.3;
        } else if (hotColdRoll < 0.12) {
          // Superstar cold night (12% chance)
          varianceMultiplier = 0.50 + random() * 0.25;
        }
      } else if (player.ovr >= 82) {
        if (hotColdRoll > 0.80) {
          // Star great game (20% chance) - 30-55% boost
          varianceMultiplier = 1.30 + random() * 0.25;
        } else if (hotColdRoll < 0.15) {
          // Star cold night
          varianceMultiplier = 0.55 + random() * 0.25;
        }
      } else if (hotColdRoll < 0.15) {
        // Regular players just have cold nights occasionally
        varianceMultiplier = 0.60 + random() * 0.25;
      }

      points = Math.max(0, Math.round(basePoints * varianceMultiplier));
      pointsRemaining -= points;
    }

    // Calculate shooting stats based on points and player OVR
    const fgPercent = 0.38 + (player.ovr / 100) * 0.22; // 38-60% based on OVR
    const tpPercent = 0.28 + (player.ovr / 100) * 0.17; // 28-45% 3PT
    const ftPercent = 0.65 + (player.ovr / 100) * 0.25; // 65-90% FT

    // Estimate shot distribution
    const threePointRate = player.pos === 'C' ? 0.15 : player.pos === 'PF' ? 0.25 : 0.35;
    const freeThrowRate = 0.20;

    const pointsFrom3 = Math.round(points * threePointRate);
    const pointsFromFT = Math.round(points * freeThrowRate);
    const pointsFrom2 = Math.max(0, points - pointsFrom3 - pointsFromFT);

    const tpm = Math.floor(pointsFrom3 / 3);
    const tpa = Math.max(tpm, Math.round(tpm / Math.max(0.25, tpPercent)));

    const ftm = pointsFromFT;
    const fta = Math.max(ftm, Math.round(ftm / Math.max(0.5, ftPercent)));

    const fgmFrom2 = Math.floor(pointsFrom2 / 2);
    const fgm = fgmFrom2 + tpm;
    const fga = Math.max(fgm, Math.round(fgm / Math.max(0.3, fgPercent)));

    // Other stats based on position and minutes
    const rebounds = Math.max(0, Math.round(
      (player.pos === 'C' ? 8 : player.pos === 'PF' ? 6 : 3) * 
      (minutes / 36) * 
      (player.ovr / 75) *
      (random() * 0.4 + 0.8) // 80-120% variance
    ));

    const assists = Math.max(0, Math.round(
      (player.pos === 'PG' ? 7 : player.pos === 'SG' ? 3 : 2) * 
      (minutes / 36) * 
      (player.ovr / 75) *
      (random() * 0.4 + 0.8)
    ));

    const steals = Math.max(0, Math.round(
      (1.2 + random() * 0.5) * 
      (minutes / 36) * 
      (player.ovr / 85)
    ));

    const blocks = Math.max(0, Math.round(
      (player.pos === 'C' ? 1.8 : player.pos === 'PF' ? 0.8 : 0.2) * 
      (minutes / 36) * 
      (player.ovr / 75)
    ));

    const turnovers = Math.max(0, Math.round(
      (player.pos === 'PG' ? 2.5 : 1.5) * 
      (minutes / 36) * 
      (1.2 - player.ovr / 100) // Better players turn it over less
    ));

    const fouls = Math.max(0, Math.round(
      2 * (minutes / 36) * (random() * 0.6 + 0.7)
    ));

    boxScore.push({
      playerId: player.id,
      playerName: `${player.firstName} ${player.lastName}`,
      minutes,
      points,
      fgm,
      fga,
      tpm,
      tpa,
      ftm,
      fta,
      rebounds,
      assists,
      steals,
      blocks,
      turnovers,
      fouls,
    });
  });

  // Add DNP entries for players outside rotation
  dnp.forEach(player => {
    boxScore.push({
      playerId: player.id,
      playerName: `${player.firstName} ${player.lastName}`,
      minutes: 0,
      points: 0,
      fgm: 0,
      fga: 0,
      tpm: 0,
      tpa: 0,
      ftm: 0,
      fta: 0,
      rebounds: 0,
      assists: 0,
      steals: 0,
      blocks: 0,
      turnovers: 0,
      fouls: 0,
    });
  });

  return boxScore;
}

// Legacy function - kept for backwards compatibility
export function generatePlayerGameStats(player, isStarter, teamWon, requestedMinutes = null) {
  const basePPG = getBasePPG(player.ovr, player.pos);
  const variance = getGameVariance();
  const minutes = getMinutesPlayed(isStarter, requestedMinutes);

  const winBonus = teamWon ? 2 + random() * 1.5 : 0;

  const pointsPerMinute = (basePPG + variance + winBonus) / 36;
  const points = Math.max(0, Math.round(pointsPerMinute * minutes));

  const rebounds = Math.max(0, Math.round(
    (player.pos === 'C' ? 8 : player.pos === 'PF' ? 6 : 3) * 
    (minutes / 36) * 
    (player.ovr / 80)
  ));

  const assists = Math.max(0, Math.round(
    (player.pos === 'PG' ? 6 : player.pos === 'SG' ? 3 : 2) * 
    (minutes / 36) * 
    (player.ovr / 80)
  ));

  const steals = Math.max(0, Math.round(
    (1 + random() * 0.5) * 
    (minutes / 36) * 
    (player.ovr / 90)
  ));

  const blocks = Math.max(0, Math.round(
    (player.pos === 'C' ? 1.5 : player.pos === 'PF' ? 0.5 : 0.1) * 
    (minutes / 36) * 
    (player.ovr / 80)
  ));

  return { points, rebounds, assists, steals, blocks, minutes };
}
